def _geopoly_select_matplotlib_backend():
    """Seleciona backend seguro para GUI e para exportação headless.

    Em Windows/macOS mantemos TkAgg por padrão. Em Linux/servidor sem DISPLAY,
    usa Agg automaticamente para permitir importação e exportação PDF/SVG em modo
    batch sem quebrar. O usuário pode forçar com MPLBACKEND/GEOPOLY_MPL_BACKEND.
    """
    forced = os.environ.get("GEOPOLY_MPL_BACKEND") or os.environ.get("MPLBACKEND")
    if forced:
        try:
            matplotlib.use(forced)
            return forced
        except Exception:
            pass
    headless = (os.name != 'nt' and not os.environ.get('DISPLAY') and not os.environ.get('WAYLAND_DISPLAY'))
    if headless:
        matplotlib.use("Agg")
        return "Agg"
    try:
        matplotlib.use("TkAgg")
        return "TkAgg"
    except Exception:
        matplotlib.use("Agg")
        return "Agg"

