def _native_edge_direction_in_face_v272g(face, a, b):
    """Return +1 if face traverses a->b, -1 if b->a, 0 otherwise."""
    m = len(face)
    for i in range(m):
        u = face[i]
        v = face[(i + 1) % m]
        if u == a and v == b:
            return 1
        if u == b and v == a:
            return -1
    return 0


def _consistent_face_orientation_v272g(faces):
    """Combinatorial BFS orientation used natively by Polyhedron/HalfEdgeMesh."""
    faces = [list(f) for f in faces]
    e2f = defaultdict(list)
    for fi, face in enumerate(faces):
        for i in range(len(face)):
            a, b = face[i], face[(i + 1) % len(face)]
            e2f[tuple(sorted((a, b)))].append(fi)
    if not e2f or any(len(fs) != 2 for fs in e2f.values()):
        return faces, False, ['malha não fechada/manifold para orientação automática']
    adj = defaultdict(list)
    for edge, fs in e2f.items():
        f0, f1 = fs
        adj[f0].append((f1, edge))
        adj[f1].append((f0, edge))
    flip = {}
    conflicts = []
    for root in range(len(faces)):
        if root in flip:
            continue
        flip[root] = False
        q = deque([root])
        while q:
            fi = q.popleft()
            face_i = list(reversed(faces[fi])) if flip[fi] else faces[fi]
            for fj, edge in adj.get(fi, []):
                a, b = edge
                di = _native_edge_direction_in_face_v272g(face_i, a, b)
                face_j0 = faces[fj]
                dj0 = _native_edge_direction_in_face_v272g(face_j0, a, b)
                face_j1 = list(reversed(face_j0))
                dj1 = _native_edge_direction_in_face_v272g(face_j1, a, b)
                want_flip = None
                if di != 0 and dj0 != 0 and di + dj0 == 0:
                    want_flip = False
                elif di != 0 and dj1 != 0 and di + dj1 == 0:
                    want_flip = True
                else:
                    conflicts.append((fi, fj, edge, di, dj0, dj1))
                    continue
                if fj not in flip:
                    flip[fj] = want_flip
                    q.append(fj)
                elif flip[fj] != want_flip:
                    conflicts.append((fi, fj, edge, 'flip_conflict', flip[fj], want_flip))
    new_faces = [list(reversed(f)) if flip.get(i, False) else list(f) for i, f in enumerate(faces)]
    return new_faces, (len(conflicts) == 0), conflicts


def orient_polyhedron_faces_consistently(poly, apply=True):
    """Orient a closed/manifold polyhedron combinatorially, when possible."""
    new_faces, orientable, conflicts = _consistent_face_orientation_v272g(poly.faces)
    if apply and orientable:
        poly.faces = new_faces
    return orientable, conflicts


def _poly_components_by_faces_v272g(poly):
    adj = poly.face_adjacency()
    seen = set()
    comps = 0
    for i in range(len(poly.faces)):
        if i in seen:
            continue
        comps += 1
        q = deque([i])
        seen.add(i)
        while q:
            u = q.popleft()
            for v, _ in adj.get(u, []):
                if v not in seen:
                    seen.add(v)
                    q.append(v)
    return comps


def _is_toroidal_like_polyhedron_v272g(poly):
    fam = (getattr(poly, 'family', '') or '').lower()
    name = (getattr(poly, 'name', '') or '').lower()
    status = (getattr(getattr(poly, 'meta', None), 'status', '') or '').lower()
    return ('toroid' in fam or 'toroid' in status or 'toro' in name or 'császár' in name or 'szilassi' in name)

class Polyhedron:
    def __init__(self, vertices, faces, name="Poliedro", family="Geral", note="", meta:Optional[GeometryMeta]=None):
        self.vertices=np.array(vertices,dtype=float); self.faces=[list(map(int,f)) for f in faces if len(f)>=3]
        self.name=str(name); self.family=str(family); self.note=str(note or ""); self.meta=meta or GeometryMeta(); self.remove_degenerate_faces(); self.orient_faces_outward_hint()
    def remove_degenerate_faces(self):
        clean=[]; n=len(self.vertices)
        for f in self.faces:
            ff=[]
            for idx in f:
                if 0<=idx<n and (not ff or ff[-1]!=idx): ff.append(idx)
            if len(ff)>2 and ff[0]==ff[-1]: ff=ff[:-1]
            if len(set(ff))>=3: clean.append(ff)
        self.faces=clean
    def face_center(self,face): return np.mean(self.vertices[list(face)],axis=0)
    def face_normal_raw(self,face):
        pts=self.vertices[list(face)]; n=np.zeros(3)
        for i in range(len(pts)):
            p,q=pts[i],pts[(i+1)%len(pts)]
            n[0]+=(p[1]-q[1])*(p[2]+q[2]); n[1]+=(p[2]-q[2])*(p[0]+q[0]); n[2]+=(p[0]-q[0])*(p[1]+q[1])
        return n
    def face_normal(self,face):
        n=self.face_normal_raw(face); L=np.linalg.norm(n); return n/L if L>EPS else np.zeros(3)
    def orient_faces_outward_hint(self):
        if len(self.vertices)==0: return
        c=np.mean(self.vertices,axis=0); out=[]
        for f in self.faces:
            fc=self.face_center(f); n=self.face_normal(f)
            out.append(list(reversed(f)) if np.linalg.norm(n)>EPS and np.dot(n,fc-c)<0 else list(f))
        self.faces=out
    def edges(self):
        s=set()
        for f in self.faces:
            for i in range(len(f)):
                a,b=f[i],f[(i+1)%len(f)]
                if a!=b: s.add(tuple(sorted((a,b))))
        return sorted(s)
    def directed_edges(self): return [(f[i],f[(i+1)%len(f)],fi) for fi,f in enumerate(self.faces) for i in range(len(f))]
    def edge_to_faces(self):
        d=defaultdict(list)
        for fi,f in enumerate(self.faces):
            for i in range(len(f)): d[tuple(sorted((f[i],f[(i+1)%len(f)])))].append(fi)
        return dict(d)
    def face_adjacency(self):
        adj=defaultdict(list)
        for e,fs in self.edge_to_faces().items():
            if len(fs)==2:
                a,b=fs; adj[a].append((b,e)); adj[b].append((a,e))
        return dict(adj)
    def euler(self):
        used={v for f in self.faces for v in f}; V=len(used); E=len(self.edges()); F=len(self.faces); return EulerResult(V,E,F,V-E+F)
    def face_histogram(self): return dict(sorted(Counter(len(f) for f in self.faces).items()))
    def vertex_valences(self):
        adj=defaultdict(set)
        for a,b in self.edges(): adj[a].add(b); adj[b].add(a)
        return [len(adj[i]) for i in range(len(self.vertices))]
    def triangulated_faces(self):
        tris=[]
        for f in self.faces:
            if len(f)==3: tris.append(list(f))
            else:
                for i in range(1,len(f)-1): tris.append([f[0],f[i],f[i+1]])
        return tris
    def face_area(self,face):
        if len(face)<3: return 0.0
        p0=self.vertices[face[0]]; area=0.0
        for i in range(1,len(face)-1): area += 0.5*np.linalg.norm(np.cross(self.vertices[face[i]]-p0,self.vertices[face[i+1]]-p0))
        return float(area)
    def area(self): return float(sum(self.face_area(f) for f in self.faces))
    def volume_signed(self):
        vol=0.0
        for tri in self.triangulated_faces():
            p0,p1,p2=self.vertices[tri]; vol += np.dot(p0,np.cross(p1,p2))/6.0
        return float(vol)
    def volume_abs(self): return abs(self.volume_signed())
    def edge_lengths(self): return [float(np.linalg.norm(self.vertices[b]-self.vertices[a])) for a,b in self.edges()]
    def bbox_dims(self): return np.max(self.vertices,axis=0)-np.min(self.vertices,axis=0) if len(self.vertices) else np.zeros(3)
    def validate(self):
        """Validate topology/orientation using the final v25.0.11/v27.2g native logic.

        This method used to be overridden by late class monkey-patches. In v27.2g
        the final behavior is defined directly here, so Polyhedron owns its method.
        """
        er = self.euler()
        e2f = self.edge_to_faces()
        boundary = sum(1 for fs in e2f.values() if len(fs) == 1)
        non = sum(1 for fs in e2f.values() if len(fs) > 2)
        closed = boundary == 0 and bool(e2f)
        manifold = bool(e2f) and all(len(fs) == 2 for fs in e2f.values())
        comps = _poly_components_by_faces_v272g(self)
        orient = False
        conflicts = []
        if closed and manifold:
            _, orient, conflicts = _consistent_face_orientation_v272g(self.faces)
        genus = (2 - er.chi) / 2 if (closed and manifold and orient and comps == 1) else None
        msg = 'malha fechada, manifold e orientável' if (closed and manifold and orient) else ('malha fechada/manifold, mas orientação exige atenção' if closed and manifold else 'malha com bordas abertas ou arestas não-manifold')
        if conflicts:
            msg += f' ({len(conflicts)} conflito(s) de orientação)'
        return ValidationResult(bool(closed), bool(manifold), bool(orient), int(comps), int(boundary), int(non), int(er.chi), None if genus is None else float(genus), msg)
@dataclass
class CatalogItem:
    key:str; name:str; family:str; note:str; vertices:List[List[float]]; faces:List[List[int]]; meta:GeometryMeta
    def build(self):
        """Build a Polyhedron using the final v25.1/v27.2g native policy.

        Johnson solids are formal by default when the embedded/offline bundle is
        available. Emergency fallback remains possible only through the documented
        environment variable. Toroidal-like entries are oriented before return.
        """
        is_johnson = self.family.startswith('Johnson') or self.key.startswith('Johnson / J')
        if is_johnson:
            formal = try_build_formal_johnson(self)
            if formal is not None:
                p = formal
            else:
                env_name = 'GEOPOLY_ALLOW_JOHNSON_FALLBACK'
                fallback_enabled = os.environ.get(env_name, '').strip().lower() in {'1', 'true', 'yes', 'sim', 'on'}
                if not fallback_enabled:
                    j = _johnson_number_from_item(self)
                    raise FileNotFoundError(
                        f'Johnson J{j:02d} formal não disponível. A v25.1+ não usa fallback didático por padrão.\n'
                        f'Instale os arquivos formais Exact Johnson Solids: clique em "Instalar Johnson formal" na interface, '
                        f'ou coloque j1..j92 em ./johnson_exact/, ou gere geopoly_johnson_offline_bundle.b64z.\n'
                        f'Fallback emergencial só se você definir {env_name}=1.'
                    )
                meta = GeometryMeta(
                    'emergency_fallback',
                    'Fallback didático Johnson ativado explicitamente por variável de ambiente.',
                    'NÃO É O SÓLIDO JOHNSON REAL. Use somente para demonstração de interface; não use como geometria formal.',
                    ['johnson', 'fallback', 'emergency'],
                    None,
                )
                note = (self.note or '') + '\nFallback emergencial v25.1: geometria didática, não formal.'
                p = Polyhedron(self.vertices, self.faces, self.name, self.family, note, meta)
        else:
            p = Polyhedron(self.vertices, self.faces, self.name, self.family, self.note, self.meta)
        if _is_toroidal_like_polyhedron_v272g(p):
            orient_polyhedron_faces_consistently(p, apply=True)
        return p
def _load_embedded_catalog():
    raw=zlib.decompress(base64.b64decode(CATALOG_B64_ZLIB.encode('ascii'))); data=json.loads(raw.decode('utf-8')); items=[]
    for d in data:
        meta=GeometryMeta(d.get('geometry_status','unknown'),d.get('geometry_source','embedded v22.4 consolidated dataset'),d.get('geometry_warning',''),d.get('tags') or [],d.get('expected_signature'))
        items.append(CatalogItem(d['key'],d['name'],d['family'],d.get('note',''),d['vertices'],d['faces'],meta))
    return items

def _geometry_status_rank(status: str) -> int:
    order = {
        'canonical': 100, 'canonical_dual': 95, 'formal': 90,
        'procedural': 70, 'procedural_school': 68, 'procedural_revolution_faceted': 66,
        'procedural_conway': 64, 'procedural_geodesic': 62, 'procedural_goldberg': 60,
        'generalized_toroidal': 58, 'generalized_compound': 55,
        'experimental_star': 30, 'experimental_star_proxy': 25,
        'approx': 20, 'fallback': 10, 'unknown': 0,
    }
    return order.get(str(status), 0)

def deduplicate_catalog_items(items: List[CatalogItem]) -> List[CatalogItem]:
    """Remove duplicatas produzidas pela consolidação v23.0.

    Critério:
    1) mantém a primeira chave única;
    2) para pares (família, nome), mantém a entrada de maior confiabilidade;
    3) preserva ordem estável do catálogo final.
    """
    by_key = []
    seen_keys = set()
    for it in items:
        if it.key in seen_keys:
            continue
        seen_keys.add(it.key)
        by_key.append(it)
    best = {}
    pos = {}
    for idx, it in enumerate(by_key):
        k = (it.family, it.name)
        if k not in best:
            best[k] = it; pos[k] = idx
        else:
            if _geometry_status_rank(it.meta.status) > _geometry_status_rank(best[k].meta.status):
                best[k] = it
    return [best[k] for k in sorted(best, key=lambda kk: pos[kk])]

