def generate_tree_net(poly,root_face=0,mode='bfs'):
    if not poly.faces: return NetResult([],[],0,mode,'sem faces')
    root_face=max(0,min(int(root_face),len(poly.faces)-1)); local={i:face_local_2d(poly,i) for i in range(len(poly.faces))}; adj=poly.face_adjacency(); maps={root_face:{v:local[root_face][v].copy() for v in poly.faces[root_face]}}
