    while q:
        fi=pop(q); pmap=maps[fi]; pc=np.mean([pmap[v] for v in poly.faces[fi]],axis=0); neigh=adj.get(fi,[])
        if mode=='area': neigh=sorted(neigh,key=lambda it:-poly.face_area(poly.faces[it[0]]))
        if mode=='small': neigh=sorted(neigh,key=lambda it:poly.face_area(poly.faces[it[0]]))
        for fj,e in neigh:
            if fj in maps: continue
