def search_best_net(poly,max_roots=40):
    n=len(poly.faces)
    if n==0: return NetResult([],[],0,'none','sem faces')
    roots=list(dict.fromkeys(sorted(range(n),key=lambda i:-poly.face_area(poly.faces[i]))[:max_roots]+list(range(min(n,max_roots)))))[:max_roots]; best=None
    for r in roots:
        for mode in ['bfs','dfs','area','small']:
            net=generate_tree_net(poly,r,mode)
            if best is None or net.overlap_count<best.overlap_count: best=net
            if net.overlap_count==0: return net
