def sheet_bbox(sheet):
    pts=np.vstack([nf.poly2d for nf in sheet]) if sheet else np.zeros((1,2)); mn=pts.min(axis=0); mx=pts.max(axis=0); return mn[0],mn[1],mx[0],mx[1]
def estimate_page_fit(sheets,page='A4',scale_mm=50.0,margin_mm=10.0):
    # v23.2.1: força tipos nativos de Python no relatório.
    # Sem isso, comparações com valores NumPy geram numpy.bool_, que o json.dumps
    # do Tkinter não serializa e causava: "Object of type bool is not JSON serializable".
    dims0={'A4':(210,297),'Carta':(215.9,279.4),'Letter':(215.9,279.4)}.get(page,(210,297))
    dims=(float(dims0[0]), float(dims0[1]))
    usable=(float(dims[0]-2*margin_mm), float(dims[1]-2*margin_mm))
    rows=[]
    for i,sheet in enumerate(sheets,1):
        x0,y0,x1,y1=sheet_bbox(sheet)
        w=float((x1-x0)*scale_mm)
        h=float((y1-y0)*scale_mm)
        fits_bool=bool((w<=usable[0] and h<=usable[1]) or (h<=usable[0] and w<=usable[1]))
        sugg=float(scale_mm)
        if (not fits_bool) and float(max(x1-x0,y1-y0))>EPS:
            sugg=float(min(usable[0]/max(float(x1-x0),EPS), usable[1]/max(float(y1-y0),EPS), usable[0]/max(float(y1-y0),EPS), usable[1]/max(float(x1-x0),EPS)))
        rows.append({'sheet':int(i),'faces':int(len(sheet)),'width_mm':w,'height_mm':h,'fits':fits_bool,'suggested_scale_mm':sugg})
    return {'page':str(page),'page_dims_mm':[float(dims[0]),float(dims[1])],'margin_mm':float(margin_mm),'requested_scale_mm':float(scale_mm),'sheets':rows}
def solve_multi_sheet(poly,net=None,page='A4',scale_mm=50.0,margin_mm=10.0):
    net=net or search_best_net(poly); graph=defaultdict(set)
    for a,b in net.overlaps: graph[a].add(b); graph[b].add(a)
    color={}
    for v in sorted(range(len(poly.faces)),key=lambda i:-len(graph[i])):
        used={color[n] for n in graph[v] if n in color}; c=0
        while c in used: c+=1
        color[v]=c
    sheets=[[] for _ in range(max(color.values())+1 if color else 1)]; fdict={nf.face_index:nf for nf in net.faces}
    for fi,c in color.items(): sheets[c].append(fdict[fi])
    return MultiSheetResult(sheets,net.overlaps,net,estimate_page_fit(sheets,page,scale_mm,margin_mm))
def safe_name(s): return ''.join(ch if ch.isalnum() or ch in '-_' else '_' for ch in str(s)).strip('_') or 'poliedro'
