def write_obj(poly,path,scale_mm=50.0):
    verts=poly.vertices*scale_mm
    with open(path,'w',encoding='utf-8') as f:
        f.write(f'# {APP_NAME} v{VERSION} — {poly.name}\n')
        for p in verts: f.write(f'v {p[0]:.8f} {p[1]:.8f} {p[2]:.8f}\n')
        for face in poly.faces: f.write('f '+' '.join(str(i+1) for i in face)+'\n')
def write_stl_ascii(poly,path,scale_mm=50.0):
    verts=poly.vertices*scale_mm
    with open(path,'w',encoding='utf-8') as f:
        f.write(f'solid {safe_name(poly.name)}\n')
        for tri in poly.triangulated_faces():
            p0,p1,p2=verts[tri]; n=tri_normal(p0,p1,p2); f.write(f'  facet normal {n[0]:.8e} {n[1]:.8e} {n[2]:.8e}\n    outer loop\n')
            for p in [p0,p1,p2]: f.write(f'      vertex {p[0]:.8e} {p[1]:.8e} {p[2]:.8e}\n')
            f.write('    endloop\n  endfacet\n')
        f.write(f'endsolid {safe_name(poly.name)}\n')
def write_stl_binary(poly,path,scale_mm=50.0):
    verts=poly.vertices*scale_mm; tris=poly.triangulated_faces(); header=(f'{APP_NAME} v{VERSION} - {poly.name}'[:80]).encode('ascii',errors='ignore').ljust(80,b' ')
    with open(path,'wb') as f:
        f.write(header); f.write(struct.pack('<I',len(tris)))
        for tri in tris:
            p0,p1,p2=verts[tri]; n=tri_normal(p0,p1,p2); vals=list(n)+list(p0)+list(p1)+list(p2); f.write(struct.pack('<12fH',*(float(x) for x in vals),0))
def write_3mf_basic(poly,path,scale_mm=50.0):
    verts=poly.vertices*scale_mm; tris=poly.triangulated_faces(); vx='\n'.join(f'<vertex x="{p[0]:.6f}" y="{p[1]:.6f}" z="{p[2]:.6f}" />' for p in verts); tx='\n'.join(f'<triangle v1="{t[0]}" v2="{t[1]}" v3="{t[2]}" />' for t in tris)
