@dataclass
class TestCaseResult: name:str; ok:bool; message:str=''
@dataclass
class TestReport:
    results:List[TestCaseResult]
    @property
    def total(self): return len(self.results)
    @property
    def ok(self): return sum(1 for r in self.results if r.ok)
    @property
    def failed(self): return self.total-self.ok
    def as_text(self):
        lines=[f'GeoPoly v{VERSION} — testes internos',f'Total: {self.total}',f'OK: {self.ok}',f'Falhas: {self.failed}','']
        lines += [('OK   ' if r.ok else 'FAIL ')+r.name+((': '+r.message) if r.message else '') for r in self.results]
        return '\n'.join(lines)
