def _signature(poly: Polyhedron) -> Dict[str, Any]:
    er = poly.euler(); val = poly.validate()
    return {'V': er.V, 'E': er.E, 'F': er.F, 'chi': er.chi, 'hist': poly.face_histogram(), 'closed': val.closed, 'manifold': val.manifold}

