        ttk.Label(side,text='Sólido').pack(anchor='w',pady=(6,0)); self.combo=ttk.Combobox(side,textvariable=self.key_var,state='readonly',width=42); self.combo.pack(fill='x'); self.combo.bind('<<ComboboxSelected>>',lambda e:self.load_selected()); ttk.Button(side,text='Carregar',command=self.load_selected).pack(fill='x',pady=4)
