    def _formula_case_changed(self):
        for w in self.formula_param_frame.winfo_children(): w.destroy()
        self.formula_param_vars = {}
        case = self.formula_case_var.get(); defaults = FORMULA_DEFAULTS.get(case, {})
        for key, value in defaults.items():
            row = ttk.Frame(self.formula_param_frame); row.pack(fill='x', pady=2)
            ttk.Label(row, text=FORMULA_PARAM_LABELS.get(key, key)).pack(side='left')
            if key in ('n','m','rings'):
                var = tk.IntVar(value=int(value)); spin = ttk.Spinbox(row, from_=3 if key=='n' else 4, to=128, increment=1, textvariable=var, width=8, command=self.update_formula_lab)
            else:
                var = tk.DoubleVar(value=float(value)); spin = ttk.Spinbox(row, from_=0.01, to=1000, increment=0.1, textvariable=var, width=8, command=self.update_formula_lab)
            spin.pack(side='right')
            spin.bind('<KeyRelease>', lambda e: self.update_formula_lab())
            spin.bind('<FocusOut>', lambda e: self.update_formula_lab())
            self.formula_param_vars[key] = var
        self.update_formula_lab()

    def update_formula_lab(self):
        try:
            case = self.formula_case_var.get()
            params = {k: v.get() for k, v in self.formula_param_vars.items()}
            res = formula_lab_compute(case, params)
            self.formula_text.delete('1.0','end')
            self.formula_text.insert('end', formula_lab_text(res))
            formula_lab_plot(self.axformula, res)
            self.canvasformula.draw_idle()
        except Exception as exc:
            if hasattr(self, 'formula_text'):
                self.formula_text.delete('1.0','end')
                self.formula_text.insert('end', 'Erro no Formula Lab:\n' + str(exc))
