        self.ax3d.clear(); v=self.poly.vertices; polys=[v[f] for f in self.poly.faces]; self.ax3d.add_collection3d(Poly3DCollection(polys,alpha=.78,edgecolor='k',linewidth=.6)); self.ax3d.scatter(v[:,0],v[:,1],v[:,2],s=10); d=max(np.ptp(v,axis=0)); c=v.mean(axis=0); d=max(d,1e-3); self.ax3d.set_xlim(c[0]-d/2,c[0]+d/2); self.ax3d.set_ylim(c[1]-d/2,c[1]+d/2); self.ax3d.set_zlim(c[2]-d/2,c[2]+d/2); self.ax3d.set_box_aspect((1,1,1)); self.ax3d.set_title(f'{self.poly.name}\n{self.poly.family} | {self.poly.meta.status}'); self.canvas3d.draw_idle()
