    def update_ms_tab(self): self.ms=solve_multi_sheet(self.poly,self.net,self.page_var.get(),self.scale_var.get(),self.margin_var.get()); self.ms_text.delete('1.0','end'); self.ms_text.insert('end','Multi-Sheet Net Solver v23.0\n'+'='*34+f'\nSólido: {self.poly.name}\nSobreposições na melhor net única: {self.net.overlap_count}\nFolhas geradas: {len(self.ms.sheets)}\n\n'+json.dumps(self.ms.page_report,indent=2,ensure_ascii=False))
