        if kind=='ascii': write_stl_ascii(self.poly,Path(path),self.scale_var.get())
        elif kind=='binary': write_stl_binary(self.poly,Path(path),self.scale_var.get())
        elif kind=='obj': write_obj(self.poly,Path(path),self.scale_var.get())
