def analyze_face_combination_ui(counts):
    counts = {int(k): int(v) for k, v in counts.items() if int(v) > 0 and int(k) >= 3}
    lines = ['Verificador por Euler e dupla contagem', '='*52]
    if not counts:
        return 'Informe pelo menos uma quantidade de faces.'
    F = sum(counts.values())
    S = sum(k*v for k, v in counts.items())
    lines.append('Faces informadas: ' + ', '.join(f'{v} face(s) de {k} lado(s)' for k, v in sorted(counts.items())))
    lines.append(f'F = {F}')
    lines.append(f'Soma dos lados das faces = {S}')
    if S % 2:
        lines.append(f'Como 2E precisa ser par, E = {S}/2 não é inteiro.')
        lines.append('Conclusão: combinação incompatível com poliedro fechado.')
        return '\n'.join(lines)
    E = S//2
    V = 2 + E - F
    lines.append(f'2E = {S}, então E = {E}')
    lines.append(f'Pela relação de Euler: V = 2 + E - F = 2 + {E} - {F} = {V}')
    if V < 4:
        lines.append('Um poliedro convexo precisa de pelo menos 4 vértices.')
        lines.append('Conclusão: combinação incompatível.')
    else:
        lines.append('As condições necessárias de Euler e dupla contagem foram satisfeitas.')
        lines.append('Atenção: isso não prova existência geométrica; apenas elimina impossibilidades básicas.')
    return '\n'.join(lines)


def exercise_text_ui(poly, mode='auto'):
    er = poly.euler(); hist = poly.face_histogram(); s = sum(len(f) for f in poly.faces)
    if mode == 'arestas':
        return (f'Exercício\nUm poliedro tem V = {er.V} vértices e F = {er.F} faces. Quantas arestas ele possui?\n\n'
                f'Solução\nV - E + F = 2\n{er.V} - E + {er.F} = 2\nE = V + F - 2 = {er.V} + {er.F} - 2 = {er.E}.')
    if mode == 'dupla':
        parts = ' + '.join(f'{q}·{n}' for n,q in hist.items())
        return (f'Exercício\nUse a dupla contagem para verificar o número de arestas do {poly.name}.\n\n'
                f'Solução\nSoma dos lados das faces = {parts} = {s}\nComo cada aresta aparece em duas faces, 2E = {s}\nLogo, E = {s}/2 = {er.E}.')
    # contextual/fallback
    return (f'Exercício contextual — {poly.name}\n\n'
            f'Dados: V = {er.V}, E = {er.E}, F = {er.F}.\n'
            f'1) Verifique a relação de Euler.\n'
            f'2) Verifique a dupla contagem das arestas.\n\n'
            f'Solução\nEuler: V - E + F = {er.V} - {er.E} + {er.F} = {er.chi}.\n'
            f'Dupla contagem: soma dos lados das faces = {s}; 2E = {2*er.E}.')


